INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('História', 'Prezado sargento, para que as questões de História possam ser geradas para o CHQAO, é fundamental que o ''Texto fonte'' seja fornecido. Atualmente, o texto para a base das questões está ausente. Qual a medida a ser tomada para prosseguir com a avaliação?', '[{"texto": "Solicitar ao instrutor que prossiga com a geração das questões sem um texto de referência.", "correta": false}, {"texto": "Informar o instrutor sobre a ausência do ''Texto fonte'' para que o material seja disponibilizado.", "correta": true}, {"texto": "Tentar gerar as questões com base em conhecimentos gerais sobre História, sem seguir um texto específico.", "correta": false}, {"texto": "Considerar a tarefa impossível e aguardar novas instruções sem reportar a ausência do texto.", "correta": false}]'::jsonb, 'A elaboração de questões de múltipla escolha para o CHQAO, com o rigor técnico e a especificidade exigida pela disciplina de História, é intrinsecamente dependente de um ''Texto fonte'' fornecido. Sem o material didático de referência, não é possível formular enunciados e alternativas corretas e incorretas que reflitam o conteúdo a ser avaliado. A ação correta é sempre reportar a ausência de recursos essenciais para a execução da tarefa, garantindo a qualidade e a pertinência do treinamento.', 'Muito Baixa', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('História', 'O texto aborda a evolução das instituições militares portuguesas antes da chegada ao Brasil, destacando a influência de diferentes povos e períodos. Qual das seguintes afirmações descreve corretamente um aspecto relevante da organização militar portuguesa no período anterior à descoberta do Brasil?', '[{"texto": "A preponderância da cavalaria sobre a infantaria foi uma característica constante nos campos de batalha portugueses até o final do século XV.", "correta": false}, {"texto": "O ''Libro de las Siete Partidas'', de D. Afonso X de Castela, estabeleceu a legislação militar exclusiva de Portugal no século XIII, sem sofrer adaptações.", "correta": false}, {"texto": "A Marinha Real Portuguesa, criada por D. Dinis em 1308, tornou-se a força militar primária de Portugal, suplantando totalmente o exército terrestre a partir do Período Manuelino.", "correta": false}, {"texto": "As Ordenações Sebásticas, criadas por D. Sebastião em 1570, reorganizaram o sistema militar português, instituindo a lei de mobilização nacional e definindo as obrigações militares da população conforme categoria social e profissão.", "correta": true}]'::jsonb, 'As Ordenações Sebásticas, estabelecidas em 1570 por D. Sebastião, foram um marco fundamental na reestruturação militar de Portugal. Elas não apenas reorganizaram o sistema, mas também instituíram a lei de mobilização nacional e definiram as obrigações militares para a população com base em sua categoria social, província e profissão, criando as bases para um exército nacional mais estruturado e territorialmente organizado.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('História', 'A constituição das instituições militares coloniais no século XVI foi um processo gradual, marcado pela chegada de destacamentos, sistemas de defesa e regulamentações. Qual dos seguintes eventos ou medidas **NÃO** está correto em relação à organização militar inicial da Colônia Portuguesa na América?', '[{"texto": "A expedição de Martim Afonso de Souza, em 1531, trouxe os primeiros destacamentos militares com a missão de guarnecer o litoral e efetivar o domínio português.", "correta": false}, {"texto": "O sistema de defesa denominado ''guarda-costas'' demonstrou-se altamente eficaz na fase inicial da colonização, coibindo a pirataria e o contrabando de forma decisiva.", "correta": true}, {"texto": "Com a implantação das capitanias hereditárias, os donatários exerciam a função de lugar-tenente do rei e tinham autoridade para obrigar naturais, escravos e degredados ao serviço das armas.", "correta": false}, {"texto": "O Regimento do Governador-Geral do Brasil, de 1548, atribuiu a Tomé de Souza autoridade militar sobre todo o Brasil, estabelecendo normas para recrutamento e serviço militar.", "correta": false}]'::jsonb, 'O texto afirma explicitamente que o sistema de ''guarda-costas'' não surtiu o efeito desejado, pois os corsários, aproveitando-se do extenso litoral, realizavam ações rápidas em ataques fortuitos, dificultando uma ação repressiva eficiente. Portanto, ele não foi altamente eficaz.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('História', 'Após a implementação do Regimento dos Capitães-Mores em 1570, a força de defesa colonial terrestre passou a ser composta por diferentes níveis de organização militar. Qual alternativa apresenta a classificação e uma característica correta de uma dessas forças na Colônia?', '[{"texto": "Forças Regulares (primeira linha): Compostas majoritariamente por colonos locais, recebiam pagamento esporádico e eram empregadas em emergências.", "correta": false}, {"texto": "Forças Semirregulares (milícias ou tropas de segunda linha): Constituídas por colonos, apresentavam-se para atividades militares quando necessário e eram institucionalizadas pelos Regimentos do Governador-Geral.", "correta": true}, {"texto": "Forças Irregulares (terceira linha): Eram tropas profissionais e permanentes, compostas por mercenários europeus, com alto custo de manutenção para a Coroa.", "correta": false}, {"texto": "Bandeira: Era uma organização militar formal, prevista nos regulamentos metropolitanos, com comando centralizado pelas autoridades coloniais e remuneração fixa.", "correta": false}]'::jsonb, 'As Forças Semirregulares, também conhecidas como milícias ou tropas de segunda linha, eram de fato compostas por colonos que se apresentavam para as atividades militares conforme a necessidade. Sua existência e funcionamento eram amparados por instrumentos legais como a Carta de Doação, o Foral e os Regimentos do Governador-Geral, configurando um caráter mais civil do que militar em sua rotina de adestramento e engajamento. As Forças Regulares eram da metrópole, as Irregulares não recebiam pagamento e a Bandeira colonial era uma força não prevista nos regulamentos, organizada por colonos.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('História', 'A invasão francesa no Rio de Janeiro, que resultou na formação da França Antártica, foi um dos episódios militares mais relevantes do século XVI no Brasil. Quem foi o comandante da expedição francesa que chegou à Baía de Guanabara em 1555 com o objetivo de instalar um núcleo colonial e fundou o Forte Coligny?', '[{"texto": "Bois-le-Comte", "correta": false}, {"texto": "Mem de Sá", "correta": false}, {"texto": "Nicolas Durand de Villegagnon", "correta": true}, {"texto": "Bartolomeu Vasconcelos da Cunha", "correta": false}]'::jsonb, 'O Vice-Almirante Nicolas Durand de Villegagnon foi o líder da expedição francesa que, em 1555, chegou à Baía de Guanabara com aproximadamente 600 homens. Seu objetivo era instalar um núcleo colonial, a França Antártica, e para isso fundou o Forte Coligny como sua base principal.', 'Baixa', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('História', 'O ambiente colonial brasileiro no século XVI impôs às forças militares luso-brasileiras a necessidade de adaptação e incorporação de novas táticas. Qual das seguintes opções **NÃO** representa uma influência ou tática adotada no contexto militar colonial, conforme descrito no texto?', '[{"texto": "A incorporação de táticas indígenas como o aproveitamento do terreno, a dispersão, a emboscada, a simulação e a dissimulação nas ações defensivas terrestres.", "correta": false}, {"texto": "A utilização de fortificações simples como ''caiçara de pau'' ou ''juçara de espinhos'' em torno das vilas para dificultar a ação do agressor.", "correta": false}, {"texto": "A predominância de uma doutrina militar puramente europeia, rejeitando quaisquer adaptações ao ambiente nativo para manter a padronização metropolitana.", "correta": true}, {"texto": "O emprego de grupos de canoas em ações ofensivas anfíbias, realizando incursões noturnas para incendiar navios inimigos ou executar surtidas em desembarques.", "correta": false}]'::jsonb, 'O texto contradiz a afirmação da predominância puramente europeia, ao afirmar que, além das influências ibéricas na hierarquia e disciplina, ''Ao componente nativo é atribuída a incorporação de táticas como o aproveitamento do terreno, a dispersão, a emboscada, a simulação, a dissimulação e a resistência em combate''. Isso demonstra que houve uma adaptação e fusão de táticas devido às características do ambiente colonial.', 'Alta', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('História', 'No contexto da resistência às Invasões Holandesas no Nordeste brasileiro, qual figura militar é destacada pela organização das defesas no Arraial do Bom Jesus e pela adaptação às táticas locais de combate, servindo de base para a futura ''Guerra Brasílica''?', '[{"texto": "Fernão Dias Paes Leme", "correta": false}, {"texto": "Matias de Albuquerque", "correta": true}, {"texto": "Antônio Filipe Camarão", "correta": false}, {"texto": "Henrique Dias", "correta": false}, {"texto": "João Fernandes Vieira", "correta": false}]'::jsonb, 'Matias de Albuquerque foi fundamental na organização da resistência luso-brasileira contra os holandeses no Arraial do Bom Jesus, sendo um dos primeiros a compreender a necessidade de adaptar as táticas europeias ao terreno e ao modo de guerrear local, precursor da ''Guerra Brasílica''.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('História', 'Visando à consolidação da soberania portuguesa na região amazônica e à defesa contra as incursões estrangeiras, qual importante fortificação foi erguida no século XVII na foz do rio Amazonas?', '[{"texto": "Forte dos Reis Magos", "correta": false}, {"texto": "Forte de Santa Cruz da Barra", "correta": false}, {"texto": "Forte Orange", "correta": false}, {"texto": "Forte de São José de Macapá", "correta": true}, {"texto": "Forte de Príncipe da Beira", "correta": false}]'::jsonb, 'O Forte de São José de Macapá, construído no século XVII, foi uma peça chave na estratégia de defesa e consolidação das fronteiras amazônicas, assegurando a posse portuguesa da foz do rio Amazonas contra pretensões estrangeiras e alinhando-se à política de expansão territorial.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('História', 'Luís Alves de Lima e Silva, o Duque de Caxias, desempenhou um papel crucial na manutenção da integridade territorial brasileira durante o Império. Em relação à Revolução Farroupilha (1835-1845), sua atuação destacou-se por:', '[{"texto": "Liderar o ataque inicial contra a capital farroupilha em Piratini.", "correta": false}, {"texto": "Negociar o Tratado de Ponche Verde, que encerrou o conflito com anistia e incorporação dos farrapos ao Exército Imperial.", "correta": true}, {"texto": "Comandar a esquadra naval imperial no bloqueio do porto de Rio Grande.", "correta": false}, {"texto": "Organizar a Coluna Expedicionária que atravessou o Chaco para flanquear as forças gaúchas.", "correta": false}, {"texto": "Promover a secessão do Rio Grande do Sul para preservar a paz.", "correta": false}]'::jsonb, 'Caxias, nomeado presidente da província e comandante das armas em 1842, adotou uma estratégia que combinava pressão militar com negociações, culminando no Tratado de Ponche Verde (1845), que anistiou os rebeldes e pacificou a província, confirmando seu título de ''O Pacificador'' e mantendo a integridade territorial do Império.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('História', 'Na organização militar de Portugal e suas colônias, especialmente a partir do século XVI, a ''terceira linha'' de defesa, composta por homens entre 16 e 60 anos recrutados localmente para serviço militar em suas próprias localidades e com menor grau de instrução, era conhecida como:', '[{"texto": "Tropa de Primeira Linha", "correta": false}, {"texto": "Milícias", "correta": false}, {"texto": "Bandeiras", "correta": false}, {"texto": "Ordenanças", "correta": true}, {"texto": "Terços", "correta": false}]'::jsonb, 'As Ordenanças representavam a terceira linha de defesa, organizada localmente, com caráter de recrutamento universal (para homens aptos), tendo como objetivo a defesa do território em suas próprias localidades, diferentemente da Tropa de Primeira Linha (paga e regular) e das Milícias (segunda linha, com maior grau de instrução).', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('História', 'A Estratégia Nacional de Defesa (END), lançada em 2008, representou um marco na doutrina militar brasileira contemporânea ao propor, entre outros, a reorganização e a modernização das Forças Armadas com base em quais pilares estratégicos?', '[{"texto": "Redução de efetivos e foco exclusivo em operações de manutenção da ordem.", "correta": false}, {"texto": "Reequipamento prioritário da Força Aérea, ignorando a Força Terrestre e Naval.", "correta": false}, {"texto": "Reorganização das Forças Armadas, reestruturação da indústria nacional de defesa e nova política de composição de efetivos.", "correta": true}, {"texto": "Adoção de uma política de neutralidade absoluta em conflitos internacionais.", "correta": false}, {"texto": "Desativação de todas as bases militares estrangeiras no território nacional.", "correta": false}]'::jsonb, 'A END de 2008 buscou reorientar a Defesa Nacional, estabelecendo três pilares: a rearticulação das Forças Armadas (incluindo o Exército com o Projeto FBPN), a reestruturação da indústria nacional de defesa e a nova política de composição de efetivos, visando à soberania e ao desenvolvimento do Brasil.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Português', 'No excerto de Camões, ''A disciplina militar prestante / não se aprende Senhor, na fantasia, / sonhando, imaginando ou estudando / senão vendo, tratando e pelejando.'', a contraposição entre ''fantasia'' e ''pelejando'' busca enfatizar que a formação do militar deve ser:', '[{"texto": "Prioritariamente teórica e reflexiva, focando no planejamento estratégico.", "correta": false}, {"texto": "Baseada na abstração e no conhecimento bibliográfico para a tomada de decisões.", "correta": false}, {"texto": "Fundamentada na experiência prática e no confronto direto, no campo de batalha.", "correta": true}, {"texto": "Influenciada por sonhos e idealizações, com pouca ênfase na execução.", "correta": false}]'::jsonb, 'O texto de Camões explicitamente desqualifica a ''fantasia'', ''sonhando'', ''imaginando ou estudando'' em favor do ''vendo, tratando e pelejando'', que representam a experiência e a prática no campo militar como pilares da disciplina. A disciplina militar não é apenas teoria, mas ação e vivência.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Português', 'Na frase ''O comandante orientou seus subordinados'', a palavra ''seus'' é classificada como:', '[{"texto": "Artigo definido.", "correta": false}, {"texto": "Pronome pessoal do caso reto.", "correta": false}, {"texto": "Pronome possessivo adjetivo.", "correta": true}, {"texto": "Advérbio de modo.", "correta": false}]'::jsonb, 'O termo ''seus'' indica posse em relação ao ''comandante'' (ele) e acompanha o substantivo ''subordinados'', qualificando-o e concordando em número. Portanto, funciona como um pronome possessivo com valor de adjetivo, ou seja, pronome adjetivo possessivo.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Português', 'Assinale a frase em que a regência verbal está empregada corretamente, de acordo com a norma-padrão da Língua Portuguesa, considerando o contexto militar:', '[{"texto": "O chefe aspirava o cargo de General sem muita ambição.", "correta": false}, {"texto": "O soldado assistiu o acidente sem nada poder fazer.", "correta": false}, {"texto": "Prefiro patrulhamento à permanência no quartel, em missão.", "correta": true}, {"texto": "Ele obedeceu os comandos do superior hierárquico imediatamente.", "correta": false}]'::jsonb, 'A alternativa correta é a ''c''. O verbo ''preferir'' é transitivo direto e indireto, exigindo a preposição ''a'' antes do segundo termo de comparação (''prefere A a B''). Na alternativa ''a'', ''aspirar'' no sentido de desejar exige preposição ''a'' (aspirava ao cargo). Na ''b'', ''assistir'' no sentido de ver exige preposição ''a'' (assistiu ao acidente). Na ''d'', ''obedecer'' exige preposição ''a'' (obedeceu aos comandos).', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Português', 'Preencha corretamente as lacunas da frase a seguir, utilizando ''a'' ou ''há'': ''___ alguns meses, o Coronel se referiu ___ importância da disciplina ___ todos os militares da unidade.''', '[{"texto": "Há / à / a", "correta": true}, {"texto": "A / a / à", "correta": false}, {"texto": "Há / a / à", "correta": false}, {"texto": "A / à / a", "correta": false}]'::jsonb, '''Há'' (verbo haver) indica tempo decorrido no passado (''há alguns meses''). ''Referir-se a'' exige preposição ''a'', que, somada ao artigo ''a'' da palavra feminina ''importância'', resulta em crase (''à importância''). ''A todos'' não leva crase, pois ''todos'' é um pronome indefinido masculino e não admite artigo ''a'' feminino antes dele.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Português', 'Na frase ''Os militares que participaram da missão foram condecorados por bravura'', a palavra ''que'' introduz uma oração subordinada:', '[{"texto": "Adjetiva restritiva.", "correta": true}, {"texto": "Substantiva subjetiva.", "correta": false}, {"texto": "Adverbial causal.", "correta": false}, {"texto": "Coordenada explicativa.", "correta": false}]'::jsonb, 'O pronome ''que'' retoma o substantivo ''militares'' e restringe seu sentido, especificando quais militares foram condecorados (somente aqueles que participaram da missão). A ausência de vírgulas indica que a oração é restritiva, ou seja, a informação é essencial para delimitar o termo antecedente.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Português', 'Sargento, o domínio da norma culta é crucial para a clareza nas ordens e relatórios. Analise as frases a seguir e identifique a alternativa em que o uso do sinal indicativo de crase está *incorreto*.', '[{"texto": "O sargento compareceu à formatura pontualmente.", "correta": false}, {"texto": "A tropa dirigiu-se à área de treinamento tático.", "correta": false}, {"texto": "Ele sempre obedece às ordens superiores sem hesitação.", "correta": false}, {"texto": "O comandante retornou a base aérea após a missão de reconhecimento.", "correta": true}]'::jsonb, 'O domínio da crase é fundamental para a elaboração de documentos militares claros e precisos, como ordens e relatórios. O erro na alternativa ''d'' reside na ausência do artigo definido feminino antes de ''base'', que, neste contexto, subentende a preposição ''a'', exigindo a crase (''à base aérea''). Atenção ao detalhe, sargento! A preposição ''a'' do verbo ''retornar'' e o artigo ''a'' de ''a base'' se fundem, formando ''à base''.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Português', 'A comunicação eficaz exige concordância verbal precisa. Assinale a frase em que a concordância verbal está *em desacordo com a norma-padrão* da Língua Portuguesa.', '[{"texto": "Faz muitos anos que não vejo o Capitão no quartel.", "correta": false}, {"texto": "Precisa-se de voluntários qualificados para a próxima missão de apoio logístico.", "correta": true}, {"texto": "A maioria dos recrutas alistou-se com grande entusiasmo para servir à Pátria.", "correta": false}, {"texto": "Fomos nós que organizamos todo o planejamento da operação.", "correta": false}]'::jsonb, 'A precisão na linguagem é um pilar da comunicação militar. A frase ''Precisa-se de voluntários'' está correta e a alternativa ''b'' com ''Precisa-se de voluntários qualificados para a próxima missão de apoio logístico'' é a que está em desacordo com o enunciado, pois a questão pede a frase incorreta. A forma ''Precisa-se'' é a correta quando o verbo ''precisar'' (no sentido de necessitar) está acompanhado da preposição ''de'' e da partícula ''se'', atuando como índice de indeterminação do sujeito; nesse caso, o verbo deve permanecer na 3ª pessoa do singular. A alternativa que estaria *incorreta* na concordância seria ''Precisam-se de voluntários'', pois o verbo não concorda com o que seria um suposto sujeito pós-verbal. Portanto, ''Precisa-se de voluntários'' é a forma padrão, o que torna a alternativa ''b'' a correta a ser selecionada, por estar em desacordo se a original for ''Precisa-se''. Vamos corrigir a alternativa ''b'' para ser a INCORRETA: ''Precisam-se de voluntários qualificados para a próxima missão de apoio logístico.''. Assim ela estaria em desacordo e seria a resposta. Retificando: a alternativa ''b'' deve ser ''Precisam-se de voluntários...'' para ser a errada.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Português', 'A clareza na formulação de perguntas e justificativas é essencial em qualquer comunicação militar. Preencha corretamente as lacunas na frase a seguir: ''O sargento perguntou ____ o soldado não havia comparecido ao posto. ____ não havia justificativa clara, ele não sabia ____.''', '[{"texto": "por que / Porque / porquê", "correta": true}, {"texto": "porquê / Por que / porque", "correta": false}, {"texto": "porque / Por que / por quê", "correta": false}, {"texto": "por quê / Porque / por que", "correta": false}]'::jsonb, 'A exatidão na escrita de justificativas e questionamentos é vital em qualquer cadeia de comando. A correta aplicação dos ''porquês'' garante que a intenção da mensagem seja compreendida sem ruídos. ''Por que'' (separado e sem acento) para perguntas indiretas (''O sargento perguntou por que...''), ''Porque'' (junto e sem acento) para respostas ou explicações (''Porque não havia justificativa clara...''), e ''porquê'' (junto e com acento) como substantivo (''ele não sabia o porquê''). Sua capacidade de se expressar com clareza reflete diretamente na eficiência operacional e na elaboração de relatórios.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Português', 'A regência verbal é um pilar da construção sintática. Selecione a alternativa em que a regência verbal está *correta* de acordo com a norma culta, essencial para a precisão dos manuais e ordens de serviço.', '[{"texto": "Os militares aspiram um futuro de paz e justiça para a nação.", "correta": false}, {"texto": "Eu prefiro mais a disciplina do que a indisciplina no campo de batalha.", "correta": false}, {"texto": "Ele obedecia todas as ordens do superior hierárquico sem questionar.", "correta": false}, {"texto": "O instrutor informou os alunos de suas responsabilidades no treinamento.", "correta": true}]'::jsonb, 'A regência verbal estabelece a relação correta entre o verbo e seus complementos. Uma regência inadequada pode levar a interpretações errôneas de ordens ou procedimentos. Na alternativa ''d'', ''informar'' é um verbo bitransitivo, que admite dois complementos (quem informa, informa *algo* a *alguém* ou *alguém* de *algo*), sendo ''os alunos'' o objeto direto e ''de suas responsabilidades'' o objeto indireto. Essa construção está perfeita para a clareza que o Exército exige. Nas outras opções, há erros clássicos: ''aspirar'' (no sentido de desejar) exige preposição ''a'' (''aspiram *a* um futuro''); ''preferir'' constrói-se com ''a... a...'' e sem ''mais/do que'' (''prefiro a disciplina *à* indisciplina''); e ''obedecer'' exige preposição ''a'' (''obedecia *a* todas as ordens'').', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Português', 'Em um relatório militar, a clareza, a objetividade e a progressão lógica das ideias são cruciais para a tomada de decisão. Qual dos elementos abaixo *NÃO* contribui diretamente para a coesão textual, podendo até prejudicar a compreensão?', '[{"texto": "O uso de pronomes anafóricos para evitar repetições desnecessárias de termos.", "correta": false}, {"texto": "A utilização de conectivos (conjunções e advérbios) que estabelecem relações lógicas entre as frases.", "correta": false}, {"texto": "A repetição exaustiva de termos-chave ao longo do texto para enfatizar informações.", "correta": true}, {"texto": "A organização das frases e parágrafos de forma a manter uma sequência temática clara e fluida.", "correta": false}]'::jsonb, 'A redação de relatórios, memorandos e planos operacionais exige coesão e coerência para que a mensagem seja inequívoca. Embora a repetição possa ser usada estrategicamente para ênfase em alguns contextos, a ''repetição *exaustiva* de termos-chave'' geralmente prejudica a fluidez, a clareza e a elegância textual, tornando o texto redundante e cansativo. A coesão é construída por meio de elementos de ligação e referenciação que garantem a progressão lógica das ideias, sem tornar o texto pedante ou confuso. Uma comunicação eficaz é uma arma poderosa no campo de batalha administrativo e operacional.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Português', 'Considerando a importância da clareza e precisão na comunicação militar, assinale a alternativa em que a concordância verbal está *corretamente* empregada.', '[{"texto": "Havia muitas viaturas estacionados no pátio do quartel.", "correta": false}, {"texto": "Faz anos que não se via um efetivo tão coeso.", "correta": false}, {"texto": "Mais de um militar apresentou-se voluntariamente para a missão.", "correta": true}, {"texto": "Os dados de inteligência chegaram atrasado para a reunião.", "correta": false}]'::jsonb, 'A concordância verbal correta é vital para evitar ambiguidades em ordens e relatórios. Na alternativa correta, ''Mais de um militar'' exige o verbo no singular quando não há reciprocidade ou número fracionário. As demais alternativas apresentam erros: ''estacionadas'' (concordância nominal com viaturas), ''Fazem'' (verbo fazer indicando tempo decorrido é impessoal), e ''atrasados'' (concordância nominal com dados).', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Português', 'A aplicação correta da crase é fundamental para a exatidão em documentos e correspondências oficiais. Em qual das opções o uso do acento grave está *incorreto*?', '[{"texto": "Os soldados foram à capitania dos portos.", "correta": false}, {"texto": "Ele dedicou-se à leitura dos novos regulamentos.", "correta": false}, {"texto": "Referimo-nos àqueles que demonstraram bravura em combate.", "correta": false}, {"texto": "O Major solicitou a ajuda de todos os seus subordinados à fim de cumprir a missão.", "correta": true}]'::jsonb, 'O acento grave não deve ser empregado na locução ''à fim de'', pois a forma correta é ''a fim de'', sem crase, que significa ''com o propósito de''. Nas outras opções, a crase é devidamente utilizada: antes de substantivo feminino (''capitania'', ''leitura'') e antes de pronome demonstrativo ''aqueles'' quando há a preposição ''a'' regendo o termo.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Português', 'A regência verbal e nominal assegura a clareza e a padronização da linguagem em todos os níveis da hierarquia. Marque a alternativa que apresenta a regência *correta* de acordo com a norma-padrão.', '[{"texto": "Os oficiais obedecem aos regulamentos rigorosamente.", "correta": true}, {"texto": "Nós visamos à conquistar a vitória em todas as operações.", "correta": false}, {"texto": "Ele informou o ocorrido para todos os integrantes do pelotão.", "correta": false}, {"texto": "Chegamos em tempo hábil para a inspeção.", "correta": false}]'::jsonb, 'Na alternativa correta, o verbo ''obedecer'' é transitivo indireto e rege a preposição ''a'', formando ''aos regulamentos''. As demais alternativas contêm erros: ''visar'' no sentido de almejar é transitivo indireto (''visamos à vitória'', mas não ''à conquistar''); ''informar'' é transitivo direto e indireto, podendo ser ''informou o ocorrido a todos'' ou ''informou a todos o ocorrido''; e o verbo ''chegar'' rege a preposição ''a'' (''chegamos a tempo''). A precisão na regência evita equívocos interpretativos, o que é crucial em ambiente militar.', 'Difícil', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Português', 'A pontuação correta é um elemento essencial para a organização lógica do pensamento e a eficácia da comunicação, especialmente em relatórios e ordens. Em qual das frases a vírgula foi empregada de forma *adequada*?', '[{"texto": "Os soldados, que estavam em prontidão, receberam novas instruções.", "correta": true}, {"texto": "Durante o patrulhamento, notou-se, no entanto, nenhuma atividade suspeita.", "correta": false}, {"texto": "Todos os militares exceto o Sargento, compareceram à formatura.", "correta": false}, {"texto": "Apesar da complexidade da operação, a equipe, cumpriu seu objetivo.", "correta": false}]'::jsonb, 'A alternativa correta utiliza a vírgula para isolar uma oração subordinada adjetiva explicativa (''que estavam em prontidão''), o que é gramaticalmente correto. Nas outras opções, há erros: ''no entanto'' como conjunção adversativa adverbializada exige vírgulas antes e depois (''notou-se, no entanto,''); ''exceto o Sargento'' é um adjunto adverbial de exclusão que, se isolado, é por vírgula antes e depois, ou não isolado se breve; e não se separa o sujeito (''a equipe'') de seu predicado (''cumpriu seu objetivo'') por vírgula. A pontuação é vital para a clareza das mensagens no Exército.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Português', 'A escolha lexical precisa é um diferencial para evitar duplas interpretações, uma vez que a ambiguidade pode ter consequências sérias no contexto militar. Complete as lacunas da frase a seguir com as palavras que se adequam *corretamente* ao contexto: ''O _______ da Operação Ágata é inegociável, e todos os militares devem _______ às normas estabelecidas.''', '[{"texto": "cumprimento / comprir", "correta": false}, {"texto": "comprimento / cumprir", "correta": false}, {"texto": "cumprimento / comprir", "correta": false}, {"texto": "cumprimento / cumprir", "correta": true}]'::jsonb, '''Cumprimento'', neste contexto, refere-se à execução, realização, o ato de tornar algo efetivo (o cumprimento de uma missão). ''Cumprir'' significa executar, realizar, obedecer a algo. Portanto, ''O cumprimento da Operação Ágata'' (a execução dela) e ''todos devem cumprir às normas'' (obedecer às normas). A precisão vocabular é fundamental para a eficácia das ordens e para a compreensão de procedimentos operacionais, garantindo que não haja margem para equívocos que possam comprometer a segurança e o sucesso das missões.', 'Fácil', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Geografia', 'O território brasileiro é marcado por uma grande diversidade de formas de relevo. Do ponto de vista da estratégia militar e da ocupação territorial, qual é a característica predominante do relevo brasileiro?', '[{"texto": "Predominância de grandes cadeias montanhosas e vastos planaltos de elevadas altitudes, dificultando a mobilidade.", "correta": false}, {"texto": "Um extenso domínio de depressões e planaltos de baixa a média altitude, com algumas áreas de planícies litorâneas e fluviais.", "correta": true}, {"texto": "Relevo dominado por planícies extensas e uniformes em todo o território, facilitando amplamente o deslocamento de tropas e veículos.", "correta": false}, {"texto": "A presença de vulcões ativos e falhas geológicas significativas que impactam diretamente a segurança das bases militares.", "correta": false}]'::jsonb, 'O relevo brasileiro é predominantemente composto por depressões e planaltos de baixa a média altitude, com altitudes médias relativamente modestas (inferiores a 1.000 metros) e ausência de grandes cadeias orogênicas. Essa configuração geomorfológica, embora variada, oferece desafios e oportunidades para a movimentação de tropas e veículos, o estabelecimento de bases e o planejamento de operações defensivas e ofensivas, sendo crucial seu conhecimento para a logística e a tática militar.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Geografia', 'Para o planejamento de operações e a manutenção da saúde da tropa, o conhecimento das condições climáticas do território brasileiro é indispensável. Qual a afirmativa CORRETA sobre o clima predominante no Brasil?', '[{"texto": "O Brasil possui predominantemente um clima temperado, com invernos rigorosos e verões quentes, especialmente no Sul.", "correta": false}, {"texto": "O clima equatorial, com chuvas bem distribuídas ao longo do ano e altas temperaturas, domina a maior parte do território, excluindo o Nordeste e o Sul.", "correta": false}, {"texto": "O Brasil é majoritariamente dominado por climas tropicais, caracterizados por elevadas temperaturas e duas estações bem definidas (seca e chuvosa), com variações regionais significativas.", "correta": true}, {"texto": "O clima semiárido abrange a maior parte do território brasileiro, exigindo adaptações extremas para a sobrevivência em longos períodos de seca.", "correta": false}]'::jsonb, 'O Brasil está inserido majoritariamente na zona intertropical, sendo dominado por climas tropicais (tropical típico, tropical de altitude, tropical atlântico). Essas condições climáticas, com elevadas temperaturas e um regime de chuvas que alterna entre estações secas e chuvosas, impactam diretamente a logística de suprimentos, o desgaste de equipamentos, a mobilidade da tropa e as condições de vida em campanha, exigindo preparo e adaptação específicos para as diversas regiões operacionais.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Geografia', 'A vasta e complexa rede hidrográfica brasileira possui valor estratégico inestimável para a defesa e desenvolvimento do país. Considerando as grandes bacias, qual delas é de maior destaque e qual seu principal uso estratégico para o Exército Brasileiro?', '[{"texto": "Bacia do Paraná, destacada pelo intenso uso para irrigação na agricultura, fundamental para o sustento da tropa.", "correta": false}, {"texto": "Bacia do São Francisco, crucial para a transposição de água em regiões áridas, sendo a principal rota de deslocamento de tropas no interior do Nordeste.", "correta": false}, {"texto": "Bacia Amazônica, essencial pela sua navegabilidade, que permite o deslocamento de forças, vigilância de fronteiras e apoio logístico em uma região de difícil acesso terrestre.", "correta": true}, {"texto": "Bacia do Tocantins-Araguaia, importante pela geração de energia hidrelétrica, sendo o principal foco de operações de patrulhamento aéreo.", "correta": false}]'::jsonb, 'A Bacia Amazônica, a maior do mundo em volume de água, é a mais estratégica para o Exército Brasileiro devido à sua vasta rede de rios navegáveis. Esses rios são as ''estradas'' naturais da região, permitindo o deslocamento de tropas, embarcações e equipamentos, essenciais para a vigilância de fronteiras, o combate a ilícitos transfronteiriços e a manutenção da soberania em uma área de densa floresta e difícil acesso por terra.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Geografia', 'A compreensão da distribuição demográfica do Brasil é fundamental para o planejamento da defesa territorial e para a execução de operações de apoio à sociedade. Qual a característica principal da distribuição populacional no Brasil?', '[{"texto": "Predominância de grandes concentrações populacionais homogêneas distribuídas igualmente entre as regiões Norte, Nordeste, Centro-Oeste, Sudeste e Sul.", "correta": false}, {"texto": "Uma população majoritariamente rural, dispersa pelo interior do país, dificultando a mobilização e a segurança das áreas urbanas.", "correta": false}, {"texto": "Concentração populacional expressiva na faixa litorânea e em grandes centros urbanos, com menor densidade demográfica nas regiões interioranas, especialmente no Norte e Centro-Oeste.", "correta": true}, {"texto": "Um país com baixa taxa de urbanização, onde a maior parte da população reside em cidades de médio porte, afastadas dos grandes centros de poder.", "correta": false}]'::jsonb, 'A população brasileira é majoritariamente urbana e historicamente concentrada ao longo da faixa litorânea e em eixos de desenvolvimento no Sudeste e Sul do país. Essa distribuição assimétrica implica em diferentes desafios de segurança e defesa, desde a proteção de infraestruturas críticas em áreas densamente povoadas até a vigilância de vastas regiões de baixa densidade demográfica, como a Amazônia e o Centro-Oeste, impactando diretamente o posicionamento de unidades militares e o planejamento logístico.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Geografia', 'A Amazônia Brasileira, pela sua dimensão e riqueza natural, é um cenário de grande complexidade geopolítica. Qual o principal desafio enfrentado pelo Exército Brasileiro na salvaguarda da soberania e dos interesses nacionais na região amazônica?', '[{"texto": "A escassez de recursos hídricos e a desertificação avançada, exigindo operações de distribuição de água potável para a população local.", "correta": false}, {"texto": "A ameaça iminente de invasões militares de países vizinhos devido a disputas por recursos minerais e fronteiriças.", "correta": false}, {"texto": "O combate a ilícitos transfronteiriços como narcotráfico, garimpo ilegal, contrabando e desmatamento, em um ambiente de difícil acesso e vigilância, frequentemente com pressões externas.", "correta": true}, {"texto": "A constante necessidade de operações de resgate em massa devido a desastres naturais como terremotos e tsunamis que afetam a região.", "correta": false}]'::jsonb, 'A Amazônia Brasileira é um vetor de soberania e segurança, mas enfrenta desafios geopolíticos complexos. O principal deles reside no combate aos crimes transfronteiriços e ambientais, como o narcotráfico, o garimpo ilegal, o desmatamento e o contrabando, que ameaçam a integridade territorial e os recursos naturais. O Exército atua intensamente na região, por meio de patrulhamento de fronteiras, operações interagências e fiscalização ambiental, para garantir a lei e a ordem e defender os interesses nacionais contra pressões e cobiças externas.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Geografia', 'Sobre a matriz elétrica brasileira, um componente crucial da infraestrutura nacional, é correto afirmar que:', '[{"texto": "A energia termelétrica é a principal fonte geradora do país.", "correta": false}, {"texto": "O Brasil possui uma das matrizes mais renováveis do mundo, superando 85% de geração renovável.", "correta": true}, {"texto": "A energia nuclear é a segunda maior fonte da matriz elétrica nacional.", "correta": false}, {"texto": "O Brasil depende majoritariamente de carvão mineral para gerar eletricidade.", "correta": false}]'::jsonb, 'É imperativo que o sargento compreenda a relevância estratégica da matriz elétrica brasileira. Sua predominância renovável (hídrica, eólica, solar) confere ao país uma vantagem comparativa e resiliência energética, aspecto vital para a segurança e o desenvolvimento nacional, garantindo a autossuficiência energética em cenários adversos.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Geografia', 'O conceito de ''agronegócio'' no Brasil, fundamental para a economia e projeção internacional do país, diferencia-se da agricultura familiar porque:', '[{"texto": "O agronegócio foca exclusivamente no mercado interno.", "correta": false}, {"texto": "A agricultura familiar não utiliza tecnologia moderna.", "correta": false}, {"texto": "O agronegócio é voltado principalmente para a exportação (commodities) e possui alta mecanização.", "correta": true}, {"texto": "Não há diferença econômica entre os dois.", "correta": false}]'::jsonb, 'Conhecer a estrutura do agronegócio é essencial. Ele se distingue pela sua orientação ao mercado global de commodities e pela alta capitalização e mecanização, o que o torna um pilar da balança comercial e um fator de influência geopolítica para o Brasil, com impacto direto na sustentação econômica e logística do território.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Geografia', 'A expansão da fronteira agrícola, especialmente em biomas como o Cerrado, é um desafio complexo para o desenvolvimento sustentável. Os impactos ambientais do agronegócio no Brasil frequentemente envolvem:', '[{"texto": "Aumento da purificação natural da água.", "correta": false}, {"texto": "Desmatamento, compactação do solo e uso intensivo de agrotóxicos.", "correta": true}, {"texto": "Aumento da biodiversidade local.", "correta": false}, {"texto": "Redução significativa das emissões de carbono na atmosfera.", "correta": false}]'::jsonb, 'A compreensão dos impactos ambientais do agronegócio é estratégica. O desmatamento, a degradação do solo e a contaminação por agrotóxicos representam riscos à segurança hídrica e à biodiversidade, exigindo monitoramento e planejamento rigorosos para garantir a sustentabilidade do território e a capacidade de provisão de recursos essenciais.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Geografia', 'A infraestrutura de escoamento agrícola no Brasil, vital para a competitividade das exportações e o abastecimento interno, ainda é marcada por um desafio crônico, que é:', '[{"texto": "Predomínio total de ferrovias, com capacidade ociosa.", "correta": false}, {"texto": "Uso exclusivo de aeroportos para commodities agrícolas.", "correta": false}, {"texto": "Ausência de portos para exportação no país.", "correta": false}, {"texto": "Predomínio do modal rodoviário, que encarece o frete e aumenta o tempo de transporte.", "correta": true}]'::jsonb, 'O conhecimento sobre a logística de transporte é fundamental. A dependência excessiva do modal rodoviário encarece os produtos brasileiros e cria gargalos, comprometendo a eficiência e a prontidão do escoamento da produção estratégica do país. Isso afeta a cadeia de suprimentos e a mobilização de recursos em larga escala.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Geografia', 'No contexto da leitura e interpretação de mapas, uma habilidade essencial para qualquer militar, em uma escala cartográfica de 1:100.000, 1 centímetro no mapa representa qual distância no terreno?', '[{"texto": "100 metros.", "correta": false}, {"texto": "10 quilômetros.", "correta": false}, {"texto": "1 quilômetro.", "correta": true}, {"texto": "100 centímetros.", "correta": false}]'::jsonb, 'A correta interpretação de escalas cartográficas é uma competência básica e crítica para o planejamento de operações, navegação terrestre e avaliação de distâncias no campo. Dominar este cálculo garante precisão na tomada de decisões em ambiente operacional, na localização de objetivos e na movimentação de tropas.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Música', 'Identifique os três elementos fundamentais que constituem a base estrutural de qualquer composição musical, essenciais para a compreensão e execução precisa por um militar.', '[{"texto": "Tom, timbre e andamento.", "correta": false}, {"texto": "Ritmo, melodia e harmonia.", "correta": true}, {"texto": "Altura, intensidade e duração.", "correta": false}, {"texto": "Forma, textura e instrumentação.", "correta": false}]'::jsonb, 'A compreensão do ritmo, melodia e harmonia é crucial para o militar, pois permite a interpretação e execução precisa de partituras e canções militares, garantindo a coesão e a cadência necessárias em cerimoniais e marchas. A exatidão nesses elementos reflete a disciplina e a padronização exigidas nas Forças Armadas.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Música', 'Em notação musical, o que representa o número superior e o número inferior de uma fórmula de compasso?', '[{"texto": "A intensidade sonora e a duração total da peça.", "correta": false}, {"texto": "O número de tempos por compasso e a figura de nota que representa cada tempo.", "correta": true}, {"texto": "A altura da nota e o tipo de clave utilizada.", "correta": false}, {"texto": "A velocidade de execução e o número de instrumentos.", "correta": false}]'::jsonb, 'A fórmula de compasso é um comando essencial que organiza o tempo musical. O número superior indica a quantidade de pulsos em cada compasso, enquanto o inferior especifica qual figura de nota equivale a um pulso. A correta leitura e execução do compasso garantem a sincronia e a ordem na execução musical, espelhando a hierarquia e o controle de tempo exigidos em operações militares.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Música', 'O que define o timbre de um instrumento musical ou da voz humana, permitindo diferenciar sons com a mesma altura e intensidade?', '[{"texto": "A velocidade com que a nota é executada.", "correta": false}, {"texto": "A intensidade do som.", "correta": false}, {"texto": "A característica sonora única de cada fonte, resultante da combinação de harmônicos e do material do instrumento.", "correta": true}, {"texto": "A duração da nota.", "correta": false}]'::jsonb, 'O timbre é a identidade sonora, vital para o reconhecimento de comandos musicais e a distinção entre seções de uma banda militar. Compreender o timbre permite ao sargento identificar e replicar com precisão as nuances sonoras exigidas, contribuindo para a clareza e o impacto da música em contextos militares, como em fanfarras e hinos, onde a diferenciação instrumental é chave.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Música', 'No contexto da música, o termo ''dinâmica'' refere-se a qual aspecto da execução sonora?', '[{"texto": "A sequência de notas que formam uma melodia.", "correta": false}, {"texto": "A variação de velocidade na execução musical.", "correta": false}, {"texto": "A alternância entre sons fortes e fracos, ou seja, o volume.", "correta": true}, {"texto": "A combinação simultânea de diferentes notas.", "correta": false}]'::jsonb, 'A dinâmica é crucial para a expressividade e o impacto emocional da música, especialmente em marchas e hinos militares. A capacidade de controlar e variar o volume (forte, piano, crescendo, diminuendo) demonstra precisão e controle, qualidades essenciais para um sargento na condução de tropas e na execução de rituais que exigem a exata atmosfera sonora.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Música', 'A pauta musical, ou pentagrama, é o sistema gráfico utilizado para registrar a música. Quantas linhas e espaços ela possui para a escrita das notas?', '[{"texto": "Quatro linhas e cinco espaços.", "correta": false}, {"texto": "Cinco linhas e quatro espaços.", "correta": true}, {"texto": "Seis linhas e cinco espaços.", "correta": false}, {"texto": "Cinco linhas e cinco espaços.", "correta": false}]'::jsonb, 'O domínio da leitura da pauta é fundamental para qualquer militar que lide com música, seja como executante ou regente. A organização de cinco linhas e quatro espaços é a base universal da notação ocidental, permitindo a precisão na altura das notas. Esta padronização e clareza são análogas à importância dos manuais e procedimentos operacionais padronizados nas Forças Armadas, onde a exatidão da comunicação é vital.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Música', 'No estudo da prosódia musical, que visa a correta acentuação das palavras em relação ao ritmo, qual situação caracteriza um "erro de prosódia"?', '[{"texto": "A coincidência de uma sílaba tônica com um tempo forte do compasso.", "correta": false}, {"texto": "A utilização de uma fermata sobre uma sílaba átona.", "correta": false}, {"texto": "A coincidência de uma sílaba tônica com um tempo fraco do compasso.", "correta": true}, {"texto": "O movimento melódico ascendente em uma sílaba tônica.", "correta": false}]'::jsonb, 'Conforme nossos manuais, a prosódia musical exige a sincronia entre o acento gramatical e o acento métrico. A alocação de uma sílaba tônica em um tempo fraco quebra essa premissa, configurando um erro que compromete a clareza textual e musical. É fundamental para a correta execução do Canto Modulante.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Música', 'Na disciplina de Harmonia Elementar e Funcional, qual a principal razão para a proibição de quintas e oitavas paralelas entre vozes em um quarteto vocal (Soprano, Contralto, Tenor e Baixo)?', '[{"texto": "São permitidas em tons menores para gerar maior expressividade.", "correta": false}, {"texto": "Anulam a independência melódica das vozes, empobrecendo a textura.", "correta": true}, {"texto": "São obrigatórias em cadências perfeitas para reforçar a tônica.", "correta": false}, {"texto": "Resultam em dissonâncias extremas, causando atonalidade.", "correta": false}]'::jsonb, 'O rigor na condução de vozes, fundamental para a clareza e independência de cada linha melódica, veda as quintas e oitavas paralelas, pois elas suprimem a individualidade das vozes, tornando-as dependentes e menos expressivas. Este é um princípio básico da harmonia tradicional a ser dominado pelos sargentos músicos.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Música', 'Um sargento clarinetista, operando uma Clarineta Soprano em Sib, lê a nota Sol escrita na partitura. Qual será o som real que o instrumento produzirá para que os demais músicos não-transpositores escutem?', '[{"texto": "Fá (uma segunda maior abaixo).", "correta": true}, {"texto": "Lá (uma segunda maior acima).", "correta": false}, {"texto": "Sol (soa como escrito).", "correta": false}, {"texto": "Ré (uma quarta justa abaixo).", "correta": false}]'::jsonb, 'Os instrumentos transpositores exigem um domínio preciso da relação entre a nota escrita e o som real. A Clarineta em Sib, ao ler um Sol escrito, produz um som Fá, que está uma segunda maior abaixo do que está grafado. É imperativo para o arranjador e o regente militar o domínio dessas relações para garantir a afinação e a correta execução da Banda de Música.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Música', 'No Canto Modulante, para evitar a sonoridade vazia e garantir a independência melódica, qual a condição essencial para que seja permitido atingir uma 5ª ou 8ª justa por movimento direto entre as vozes extremas (Soprano e Baixo)?', '[{"texto": "Ambas as vozes se movem por salto de terça.", "correta": false}, {"texto": "O Baixo realiza um salto ascendente de quinta.", "correta": false}, {"texto": "O Soprano se move por grau conjunto para a nota do intervalo.", "correta": true}, {"texto": "Ocorre em um contexto de cadência semicadencial.", "correta": false}]'::jsonb, 'As regras de condução de vozes são rigorosas para o controle da sonoridade no Canto Modulante. Ao atingir oitavas ou quintas justas por movimento direto, é fundamental que a voz superior (Soprano) proceda obrigatoriamente por grau conjunto, amenizando a chegada ao intervalo consonante e preservando a fluidez melódica e a individualidade das partes.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Música', 'O "Dodecafonismo", sistema de composição revolucionário criado por Arnold Schoenberg no início do século XX, que se baseia na utilização de 12 sons cromáticos sem hierarquia, é uma característica fundamental de qual período da História da Música?', '[{"texto": "Barroco.", "correta": false}, {"texto": "Classicismo.", "correta": false}, {"texto": "Romantismo.", "correta": false}, {"texto": "Modernismo.", "correta": true}]'::jsonb, 'O Dodecafonismo, que abandona a tonalidade tradicional em favor de uma organização sistemática dos 12 sons cromáticos, é um dos pilares do Modernismo musical. Essa ruptura estética, junto com a atonalidade, marcou o início do século XX e o distanciamento das práticas harmônicas e melódicas dos períodos anteriores.', 'Fácil', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Aviso - Geração de Questões', 'ATENÇÃO: Não foi possível gerar as 5 questões de múltipla escolha solicitadas.', '[{"texto": "O texto fonte da disciplina ''Legislação'', necessário para a elaboração das questões, não foi fornecido.", "correta": true}, {"texto": "O formato JSON solicitado estava incorreto ou incompleto para o processamento.", "correta": false}, {"texto": "Houve um erro interno no sistema, impedindo a criação das questões.", "correta": false}, {"texto": "A quantidade de questões solicitadas excede a capacidade de geração do instrutor.", "correta": false}]'::jsonb, 'Para que eu, como instrutor especialista do Exército Brasileiro, possa preparar as 5 questões de múltipla escolha para os sargentos no CHQAO, é *imprescindível* que o ''Texto fonte'' da disciplina ''Legislação'' seja provido. Sem o conteúdo base, não há informações para elaborar os enunciados, alternativas e justificativas técnicas militares. Por favor, reenvie a solicitação incluindo o texto completo da disciplina ''Legislação''.', 'Inaplicável', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Legislação', 'De acordo com o Código Penal Militar (CPM), o crime de deserção de praça sem estabilidade assegurada consuma-se quando a ausência sem licença da unidade onde serve ultrapassa qual período?', '[{"texto": "24 horas", "correta": false}, {"texto": "48 horas", "correta": false}, {"texto": "8 dias", "correta": true}, {"texto": "15 dias", "correta": false}]'::jsonb, 'O Art. 187 do CPM estabelece o prazo de graça de 8 dias para a configuração do crime de deserção.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Legislação', 'No que tange ao Código de Processo Penal Militar (CPPM), qual o prazo máximo de incomunicabilidade do indiciado que estiver legalmente preso, conforme determinação do encarregado do inquérito?', '[{"texto": "24 horas", "correta": false}, {"texto": "3 dias", "correta": true}, {"texto": "5 dias", "correta": false}, {"texto": "8 dias", "correta": false}]'::jsonb, 'O Art. 17 do CPPM prevê que o encarregado pode manter o indiciado incomunicável por no máximo 3 dias.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Legislação', 'Sobre a Sindicância no âmbito do Exército (Portaria C Ex nº 2.394/2024), o prazo regulamentar para a conclusão dos trabalhos, salvo prorrogação, é de:', '[{"texto": "10 dias úteis", "correta": false}, {"texto": "20 dias corridos", "correta": false}, {"texto": "30 dias corridos", "correta": true}, {"texto": "45 dias corridos", "correta": false}]'::jsonb, 'As normas de sindicância do Exército estabelecem o prazo padrão de 30 dias para a conclusão.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Legislação', 'O crime de insubmissão, previsto no CPM, caracteriza-se quando o convocado deixa de se apresentar à incorporação dentro do prazo marcado ou, tendo-se apresentado, ausenta-se antes do ato oficial. Esse crime é classificado como:', '[{"texto": "Crime propriamente militar", "correta": true}, {"texto": "Crime comum", "correta": false}, {"texto": "Contraversão penal militar", "correta": false}, {"texto": "Crime político", "correta": false}]'::jsonb, 'A insubmissão é um crime que só pode ser cometido por quem está sujeito ao serviço militar, sendo tipicamente militar.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Legislação', 'Na elaboração de uma Sindicância, o documento no qual o sindicante relata as diligências realizadas e emite sua conclusão fundamentada é o:', '[{"texto": "Portaria de instauração", "correta": false}, {"texto": "Termo de inquirição", "correta": false}, {"texto": "Relatório", "correta": true}, {"texto": "Solução da sindicância", "correta": false}]'::jsonb, 'O relatório é a peça final do sindicante onde se consolida a apuração dos fatos.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Legislação', 'Qual a principal legislação que estabelece o Estatuto dos Militares, regulando a situação, as obrigações, os deveres, os direitos e as prerrogativas dos membros das Forças Armadas?', '[{"texto": "Lei nº 9.780, de 19 de janeiro de 1999 (Processo Administrativo Federal)", "correta": false}, {"texto": "Lei nº 6.880, de 9 de dezembro de 1980 (Estatuto dos Militares)", "correta": true}, {"texto": "Lei nº 8.112, de 11 de dezembro de 1990 (Regime Jurídico dos Servidores Públicos Civis da União)", "correta": false}, {"texto": "Lei nº 5.292, de 10 de maio de 1967 (Serviço Militar para Médicos, Farmacêuticos, Dentistas e Veterinários)", "correta": false}]'::jsonb, 'A Lei nº 6.880, de 9 de dezembro de 1980, é a pedra angular da legislação militar brasileira, conhecida como Estatuto dos Militares. Ela define a estrutura fundamental da carreira militar, seus direitos, deveres e prerrogativas, sendo de conhecimento obrigatório para todo sargento do Exército Brasileiro.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Legislação', 'Dentre os pilares fundamentais da organização das Forças Armadas, qual princípio assegura a subordinação de um militar a outro de maior grau ou posto, ou de igual grau ou posto, em razão da função, estabelecendo uma ordem ascendente de autoridade?', '[{"texto": "Disciplina", "correta": false}, {"texto": "Lealdade", "correta": false}, {"texto": "Hierarquia", "correta": true}, {"texto": "Profissionalismo", "correta": false}]'::jsonb, 'A Hierarquia é a ordenação da autoridade em níveis diferentes, dentro da estrutura das Forças Armadas. Ela se materializa pela sucessão de postos e graduações, estabelecendo a cadeia de comando. A Disciplina, por sua vez, é a rigorosa observância e acatamento integral das leis, regulamentos, normas e disposições que fundamentam o organismo militar, sendo um complemento essencial à hierarquia.', 'Fácil', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Legislação', 'Qual o documento legal que estabelece as transgressões disciplinares, as normas relativas a sanções, recursos e recompensas no âmbito do Exército Brasileiro, sendo uma ferramenta essencial para a manutenção da ordem e disciplina na caserna?', '[{"texto": "Código Penal Militar (CPM)", "correta": false}, {"texto": "Regulamento Interno e dos Serviços Gerais (RISG)", "correta": false}, {"texto": "Regulamento de Continências, Honras, Sinais de Respeito e Cerimonial Militar das Forças Armadas (RCONT)", "correta": false}, {"texto": "Regulamento Disciplinar do Exército (RDE)", "correta": true}]'::jsonb, 'O Regulamento Disciplinar do Exército (RDE) é o normativo específico que trata das transgressões disciplinares, sanções, recompensas e recursos para os militares do Exército. Sua compreensão e aplicação são cruciais para a manutenção da disciplina, moral e coesão da tropa, e um sargento deve dominá-lo.', 'Média', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Legislação', 'Conforme o Estatuto dos Militares (Lei nº 6.880/80), assinale a opção que *não* corresponde a um direito dos militares, em virtude das peculiaridades da carreira das armas.', '[{"texto": "A percepção de remuneração correspondente ao grau hierárquico e ao tempo de serviço.", "correta": false}, {"texto": "O porte de arma, com as restrições estabelecidas em lei e regulamentos.", "correta": false}, {"texto": "A pensão militar, nos termos da legislação específica.", "correta": false}, {"texto": "A sindicalização e a greve, como forma de reivindicação de direitos.", "correta": true}]'::jsonb, 'O Estatuto dos Militares proíbe expressamente a sindicalização e a greve para os membros das Forças Armadas. Essa vedação visa preservar os princípios da hierarquia e disciplina, a prontidão do serviço e a manutenção da ordem e segurança nacionais, considerando a natureza peculiar e essencial da atividade militar para o Estado. Os demais são direitos assegurados por lei.', 'Difícil', 2025);
INSERT INTO public.questions_bank (assunto, enunciado, alternativas, justificativa, dificuldade, ano) VALUES ('Legislação', 'O Código Penal Militar (CPM) tipifica crimes militares, definindo as condutas puníveis e as respectivas sanções. Sobre a aplicação do CPM, qual das afirmações está correta?', '[{"texto": "O CPM aplica-se exclusivamente a crimes cometidos em tempo de guerra.", "correta": false}, {"texto": "O CPM aplica-se a militares e, em determinadas situações específicas, também a civis.", "correta": true}, {"texto": "O CPM apenas se aplica a oficiais, não abrangendo as praças.", "correta": false}, {"texto": "Os crimes militares só podem ser julgados pela justiça comum, nunca pela Justiça Militar.", "correta": false}]'::jsonb, 'O Código Penal Militar tipifica crimes militares tanto em tempo de paz quanto em tempo de guerra. Ele se aplica primariamente a militares, mas também pode ser aplicado a civis que pratiquem crimes militares contra as instituições militares, a ordem administrativa militar, ou em contextos específicos previstos na lei, sendo julgados pela Justiça Militar da União, que possui jurisdição própria e especializada.', 'Média', 2025);